41: /**
42:  * Creates a Pipeline pattern where the output of the previous step is sent as input to the next step, reusing the same
43:  * message exchanges
44:  */
45: public class Pipeline extends BaseProcessorSupport implements Navigate<Processor>, Traceable, IdAware, RouteIdAware {
46: 
47:     private static final Logger LOG = LoggerFactory.getLogger(Pipeline.class);
48: 
49:     private final CamelContext camelContext;
50:     private final ReactiveExecutor reactiveExecutor;
51:     private final List<AsyncProcessor> processors;
52:     private final int size;
53:     private PooledExchangeTaskFactory taskFactory;
54: 
55:     private String id;
56:     private String routeId;
57: 
58:     private final class PipelineTask implements PooledExchangeTask, AsyncCallback {
59: 
60:         private Exchange exchange;
61:         private AsyncCallback callback;
62:         private int index;
63: 
64:         PipelineTask() {
65:         }
66: 
67:         @Override
68:         public void prepare(Exchange exchange, AsyncCallback callback) {
69:             this.exchange = exchange;
70:             this.callback = callback;
71:             this.index = 0;
72:         }
73: 
74:         @Override
75:         public void reset() {
76:             this.exchange = null;
77:             this.callback = null;
78:             this.index = 0;
79:         }
80: 
81:         @Override
82:         public void done(boolean doneSync) {
83:             reactiveExecutor.schedule(this);
84:         }
85: 
86:         @Override
87:         public void run() {
88:             boolean stop = exchange.isRouteStop();
89:             int num = index;
90:             boolean more = num < size;
91:             boolean first = num == 0;
92: 
93:             if (!stop && more && (first || continueProcessing(exchange, "so breaking out of pipeline", LOG))) {
94: 
95:                 // prepare for next run
96:                 ExchangeHelper.prepareOutToIn(exchange);
97: 
98:                 // get the next processor
99:                 AsyncProcessor processor = processors.get(index++);
100: 
101:                 processor.process(exchange, this);
102:             } else {
103:                 // copyResults is needed in case MEP is OUT and the message is not an OUT message
104:                 ExchangeHelper.copyResults(exchange, exchange);
105: 
106:                 // logging nextExchange as it contains the exchange that might have altered the payload and since
107:                 // we are logging the completion it will be confusing if we log the original instead
108:                 // we could also consider logging the original and the nextExchange then we have *before* and *after* snapshots
109:                 if (LOG.isTraceEnabled()) {
110:                     LOG.trace("Processing complete for exchangeId: {} >>> {}", exchange.getExchangeId(), exchange);
111:                 }
112: 
113:                 AsyncCallback cb = callback;
114:                 taskFactory.release(this);
115:                 reactiveExecutor.schedule(cb);
116:             }
117:         }
118:     }
119: 
120:     public Pipeline(CamelContext camelContext, Collection<Processor> processors) {
121:         this.camelContext = camelContext;
122:         this.reactiveExecutor = camelContext.getCamelContextExtension().getReactiveExecutor();
123:         this.processors = processors.stream().map(AsyncProcessorConverterHelper::convert).toList();
124:         this.size = processors.size();
125:     }
126: 
127:     public static Processor newInstance(CamelContext camelContext, List<Processor> processors) {
128:         if (processors.isEmpty()) {
129:             return null;
130:         } else if (processors.size() == 1) {
131:             return processors.get(0);
132:         }
133:         return new Pipeline(camelContext, processors);
134:     }
135: 
136:     public static Processor newInstance(final CamelContext camelContext, final Processor... processors) {
137:         if (processors == null || processors.length == 0) {
138:             return null;
139:         } else if (processors.length == 1) {
140:             return processors[0];
141:         }
142: 
143:         final List<Processor> toBeProcessed = new ArrayList<>(processors.length);
144:         for (Processor processor : processors) {
145:             if (processor != null) {
146:                 toBeProcessed.add(processor);
147:             }
148:         }
149: 
150:         return new Pipeline(camelContext, toBeProcessed);
151:     }
152: 
153:     @Override
154:     public boolean process(Exchange exchange, AsyncCallback callback) {
155:         try {
156:             // create task which has state used during routing
157:             PooledExchangeTask task = taskFactory.acquire(exchange, callback);
158: 
159:             if (exchange.isTransacted()) {
160:                 reactiveExecutor.scheduleQueue(task);
161:             } else {
162:                 reactiveExecutor.scheduleMain(task);
163:             }
164:             return false;
165:         } catch (Exception e) {
166:             exchange.setException(e);
167:             callback.done(true);
168:             return true;
169:         }
170:     }
171: 
172:     @Override
173:     protected void doBuild() throws Exception {
174:         boolean pooled = camelContext.getCamelContextExtension().getExchangeFactory().isPooled();
175:         if (pooled) {
176:             taskFactory = new PooledTaskFactory(getId()) {
177:                 @Override
178:                 public PooledExchangeTask create(Exchange exchange, AsyncCallback callback) {
179:                     return new PipelineTask();
180:                 }
181:             };
182:             int capacity = camelContext.getCamelContextExtension().getExchangeFactory().getCapacity();
183:             taskFactory.setCapacity(capacity);
184:         } else {
185:             taskFactory = new PrototypeTaskFactory() {
186:                 @Override
187:                 public PooledExchangeTask create(Exchange exchange, AsyncCallback callback) {
188:                     return new PipelineTask();
189:                 }
190:             };
191:         }
192:         LOG.trace("Using TaskFactory: {}", taskFactory);
193: 
194:         ServiceHelper.buildService(taskFactory, processors);
195:     }
196: 
197:     @Override
198:     protected void doInit() throws Exception {
199:         ServiceHelper.initService(taskFactory, processors);
200:     }
201: 
202:     @Override
203:     protected void doStart() throws Exception {
204:         ServiceHelper.startService(taskFactory, processors);
205:     }
206: 
207:     @Override
208:     protected void doStop() throws Exception {
209:         ServiceHelper.stopService(taskFactory, processors);
210:     }
211: 
212:     @Override
213:     protected void doShutdown() throws Exception {
214:         ServiceHelper.stopAndShutdownServices(taskFactory, processors);
215:     }
216: 
217:     @Override
218:     public String toString() {
219:         return id;
220:     }
221: 
222:     @Override
223:     public String getTraceLabel() {
224:         return "pipeline";
225:     }
226: 
227:     @Override
228:     public String getId() {
229:         return id;
230:     }
231: 
232:     @Override
233:     public void setId(String id) {
234:         this.id = id;
235:     }
236: 
237:     @Override
238:     public String getRouteId() {
239:         return routeId;
240:     }
241: 
242:     @Override
243:     public void setRouteId(String routeId) {
244:         this.routeId = routeId;
245:     }
246: 
247:     @Override
248:     public List<Processor> next() {
249:         if (!hasNext()) {
250:             return null;
251:         }
252:         return new ArrayList<>(processors);
253:     }
254: 
255:     @Override
256:     public boolean hasNext() {
257:         return processors != null && !processors.isEmpty();
258:     }
259: }
