17: package org.apache.camel.processor;
18: 
19: import org.apache.camel.Exchange;
20: import org.slf4j.Logger;
21: 
22: /**
23:  * Helper for processing {@link org.apache.camel.Exchange} in a
24:  * <a href="http://camel.apache.org/pipes-and-filters.html">pipeline</a>.
25:  */
26: public final class PipelineHelper {
27: 
28:     private PipelineHelper() {
29:     }
30: 
31:     /**
32:      * Should we continue processing the exchange?
33:      *
34:      * @param  exchange the next exchange
35:      * @param  message  a message to use when logging that we should not continue processing
36:      * @param  log      a logger
37:      * @return          <tt>true</tt> to continue processing, <tt>false</tt> to break out, for example if an exception
38:      *                  occurred.
39:      */
40:     public static boolean continueProcessing(Exchange exchange, String message, Logger log) {
41:         boolean stop = exchange.isFailed() || exchange.isRollbackOnly() || exchange.isRollbackOnlyLast()
42:                 || exchange.getExchangeExtension().isErrorHandlerHandledSet()
43:                         && exchange.getExchangeExtension().isErrorHandlerHandled();
44:         if (stop) {
45:             // The errorErrorHandler is only set if satisfactory handling was done
46:             // by the error handler. It's still an exception, the exchange still failed.
47:             if (log.isDebugEnabled()) {
48:                 StringBuilder sb = new StringBuilder(256);
49:                 sb.append("Message exchange has failed: ").append(message).append(" for exchange: ").append(exchange);
50:                 if (exchange.isRollbackOnly() || exchange.isRollbackOnlyLast()) {
51:                     sb.append(" Marked as rollback only.");
52:                 }
53:                 if (exchange.getException() != null) {
54:                     sb.append(" Exception: ").append(exchange.getException());
55:                 }
56:                 if (exchange.getExchangeExtension().isErrorHandlerHandledSet()
57:                         && exchange.getExchangeExtension().isErrorHandlerHandled()) {
58:                     sb.append(" Handled by the error handler.");
59:                 }
60:                 log.debug(sb.toString());
61:             }
62: 
63:             return false;
64:         }
65: 
66:         // check for stop
67:         if (exchange.isRouteStop()) {
68:             if (log.isDebugEnabled()) {
69:                 log.debug("ExchangeId: {} is marked to stop routing: {}", exchange.getExchangeId(), exchange);
70:             }
71:             return false;
72:         }
73: 
74:         return true;
75:     }
76: 
77: }
